<template><AppShell><section class="card"><div class="card-head"><div><p class="eyebrow">低置信度分流</p><h2>人工 Triage</h2></div><span class="badge">{{ items.length }}</span></div><article v-for="item in items" :key="item.id" class="triage-item"><div><strong>{{ item.node_name||`节点 #${item.node_id}` }}</strong><p>{{ item.issue_type }} · 置信度 {{ item.confidence.toFixed(2) }}</p><p>{{ item.reason }}</p><small>证据：{{ item.evidence||'无' }}；检测器分歧：{{ item.detector_disagreement?'是':'否' }}</small></div><div class="action-row"><button class="button primary" @click="decide(item.id,'issue')">确认问题</button><button class="button secondary" @click="decide(item.id,'clean')">确认正常</button><button class="button secondary" @click="decide(item.id,'inconclusive')">仍不确定</button></div></article><p v-if="!items.length">暂无待分流项目。</p></section></AppShell></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import AppShell from'../components/AppShell.vue';import{decideTriage,listTriage}from'../api/triage';import type{TriageItem}from'../api/triage';import{useWorkspace}from'../state/workspace';const{state}=useWorkspace();const items=ref<TriageItem[]>([]);async function load(){items.value=await listTriage(state.workflowId||'')}async function decide(id:number,d:'issue'|'clean'|'inconclusive'){await decideTriage(id,d);await load()}onMounted(load)</script>
<style scoped>.triage-item{display:grid;grid-template-columns:1fr auto;gap:20px;padding:16px 0;border-top:1px solid var(--line)}</style>
